public class CustomFoodItem extends Item {
    public CustomFoodItem(Settings settings) {
        super(settings);
    }
}

public class ModItems {
    public static final Item CUSTOM_FOOD = new Item(new Item.Settings().food(new FoodComponent.Builder().hunger(6).saturationModifier(0.6f).build()).maxCount(64));
    public static void register() {
        Registry.register(Registries.ITEM, new Identifier("modid", "custom_food"), CUSTOM_FOOD);
    }
}
